import sys

class Solution:
    def subArrayRanges(self, nums: list[int]) -> int:
        n = len(nums)
        res = 0
        for i in range(n):
            mx, mn = nums[i], nums[i]
            for j in range(i, n):
                mx = max(mx, nums[j])
                mn = min(mn, nums[j])
                res += mx - mn
        return res

