#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int subArrayRanges(vector<int>& nums) {
        int n = nums.size();
        long res = 0;
        for (int i = 0; i < n; i++) {
            int mx = nums[i], mn = nums[i];
            for (int j = i; j < n; j++) {
                mx = max(mx, nums[j]);
                mn = min(mn, nums[j]);
                res += mx - mn;
            }
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    int ans = sol.subArrayRanges(nums);
    cout << ans << "\n";
    return 0;
}
